const API_BASE = window.location.hostname === "localhost" || window.location.hostname === "127.0.0.1"
  ? "http://localhost:5000"
  : "https://mildwave-backend.onrender.com";
document.addEventListener('DOMContentLoaded', () => {
  if (typeof lucide !== 'undefined') {
    lucide.createIcons();
  }
  const navbar = document.getElementById('main-navbar');
  const scrollTopBtn = document.getElementById('scroll-top-btn');
  window.addEventListener('scroll', () => {
    if (window.scrollY > 50) {
      navbar.classList.add('scrolled');
    } else {
      navbar.classList.remove('scrolled');
    }
    if (window.scrollY > 300) {
      scrollTopBtn.classList.add('active');
    } else {
      scrollTopBtn.classList.remove('active');
    }
    trackActiveNavLinks();
  });
  const revealElements = document.querySelectorAll('.reveal');
  const revealObserver = new IntersectionObserver((entries) => {
    entries.forEach((entry) => {
      if (entry.isIntersecting) {
        entry.target.classList.add('active');
revealObserver.unobserve(entry.target);
      }
    });
  }, {
    threshold: 0.15,
    rootMargin: '0px 0px -50px 0px'
  });
  revealElements.forEach(el => revealObserver.observe(el));
  let currentSlideIndex = 0;
  const slides = document.querySelectorAll('.carousel-slide');
  const dots = document.querySelectorAll('.carousel-dot');
  let slideInterval;
  function showSlide(index) {
    if (slides.length === 0) return;
    if (index >= slides.length) {
      currentSlideIndex = 0;
    } else if (index < 0) {
      currentSlideIndex = slides.length - 1;
    } else {
      currentSlideIndex = index;
    }
    slides.forEach((slide, i) => {
      if (i === currentSlideIndex) {
        slide.classList.add('active');
      } else {
        slide.classList.remove('active');
      }
    });
    dots.forEach((dot, i) => {
      if (i === currentSlideIndex) {
        dot.classList.add('active');
      } else {
        dot.classList.remove('active');
      }
    });
    const heroSection = document.getElementById('home');
    if (heroSection) {
      const activeSlide = slides[currentSlideIndex];
      if (activeSlide && activeSlide.classList.contains('slide-light-theme')) {
        heroSection.classList.add('light-slide-active');
      } else {
        heroSection.classList.remove('light-slide-active');
      }
    }
  }
  function startAutoSlide() {
    clearInterval(slideInterval);
    slideInterval = setInterval(() => {
      showSlide(currentSlideIndex + 1);
}, 4500);
  }
  window.moveSlide = function(step) {
    showSlide(currentSlideIndex + step);
    startAutoSlide();
  };
  window.setSlide = function(index) {
    showSlide(index);
    startAutoSlide();
  };
  if (slides.length > 0) {
    showSlide(0);
    startAutoSlide();
  }
  const carouselEl = document.querySelector('.hero-carousel');
  if (carouselEl) {
    let touchStartX = 0;
    let touchEndX = 0;
    carouselEl.addEventListener('touchstart', (e) => {
      touchStartX = e.changedTouches[0].screenX;
    }, { passive: true });
    carouselEl.addEventListener('touchend', (e) => {
      touchEndX = e.changedTouches[0].screenX;
      handleSwipe();
    }, { passive: true });
    function handleSwipe() {
const swipeThreshold = 40;
      if (touchStartX - touchEndX > swipeThreshold) {
window.moveSlide(1);
      } else if (touchEndX - touchStartX > swipeThreshold) {
window.moveSlide(-1);
      }
    }
  }
  const mobileNavLinksList = document.querySelectorAll('.mobile-nav-links a');
  mobileNavLinksList.forEach(link => {
    link.addEventListener('click', () => {
      if (typeof closeMobileMenu === 'function') {
        closeMobileMenu();
      }
    });
  });
  const statNumbers = document.querySelectorAll('.stat-number');
  let statsAnimated = false;
  const countUp = (element) => {
    const target = parseInt(element.getAttribute('data-target'), 10);
const duration = 2000;
    const startTime = performance.now();
    const updateCount = (currentTime) => {
      const elapsed = currentTime - startTime;
      const progress = Math.min(elapsed / duration, 1);
      const easeProgress = progress * (2 - progress);
      const currentValue = Math.floor(easeProgress * target);
      if (target === 999) {
        const progressVal = Math.floor(easeProgress * 100);
        element.textContent = progressVal + "%";
        if (progress === 1) {
          element.textContent = "Pan India";
        }
      } else {
        element.textContent = currentValue + "+";
      }
      if (progress < 1) {
        requestAnimationFrame(updateCount);
      } else {
        if (target === 999) {
          element.textContent = "Pan India";
        } else {
          element.textContent = target + "+";
        }
      }
    };
    requestAnimationFrame(updateCount);
  };
  const aboutSection = document.querySelector('.about-company-section');
  if (aboutSection) {
    const statsObserver = new IntersectionObserver((entries) => {
      const entry = entries[0];
      if (entry.isIntersecting && !statsAnimated) {
        statNumbers.forEach(num => countUp(num));
        statsAnimated = true;
        statsObserver.unobserve(aboutSection);
      }
    }, { threshold: 0.25 });
    statsObserver.observe(aboutSection);
  }
  const roDateInput = document.getElementById('ro-date');
  if (roDateInput) {
    const tomorrow = new Date();
    tomorrow.setDate(tomorrow.getDate() + 1);
    const yyyy = tomorrow.getFullYear();
    const mm = String(tomorrow.getMonth() + 1).padStart(2, '0');
    const dd = String(tomorrow.getDate()).padStart(2, '0');
    roDateInput.min = `${yyyy}-${mm}-${dd}`;
  }
  const docDropzone = document.getElementById('doc-upload-dropzone');
  if (docDropzone) {
    docDropzone.addEventListener('dragover', (e) => {
      e.preventDefault();
      docDropzone.classList.add('selected');
    });
    docDropzone.addEventListener('dragleave', () => {
      docDropzone.classList.remove('selected');
    });
    docDropzone.addEventListener('drop', (e) => {
      e.preventDefault();
      docDropzone.classList.remove('selected');
      const files = e.dataTransfer.files;
      if (files.length > 0) {
        const fileInput = document.getElementById('upload-doc-input');
        fileInput.files = files;
        handleDocFileSelect({ target: fileInput });
      }
    });
  }
  handleRoute();
  if (typeof window.loadLegalDocuments === 'function') {
    window.loadLegalDocuments();
  }
  const careerDropzones = [
    { zoneId: 'corp-aadhaar-dropzone', inputId: 'corp-file-aadhaar', key: 'corp-aadhaar' },
    { zoneId: 'corp-resume-dropzone', inputId: 'corp-file-resume', key: 'corp-resume' },
    { zoneId: 'corp-photo-dropzone', inputId: 'corp-file-photo', key: 'corp-photo' },
    { zoneId: 'man-aadhaar-dropzone', inputId: 'man-file-aadhaar', key: 'man-aadhaar' },
    { zoneId: 'man-resume-dropzone', inputId: 'man-file-resume', key: 'man-resume' },
    { zoneId: 'man-photo-dropzone', inputId: 'man-file-photo', key: 'man-photo' }
  ];
  careerDropzones.forEach(dz => {
    const zoneEl = document.getElementById(dz.zoneId);
    const inputEl = document.getElementById(dz.inputId);
    if (zoneEl && inputEl) {
      zoneEl.addEventListener('dragover', (e) => {
        e.preventDefault();
        zoneEl.classList.add('selected');
        zoneEl.style.borderColor = 'var(--primary)';
      });
      zoneEl.addEventListener('dragleave', () => {
        zoneEl.classList.remove('selected');
        zoneEl.style.borderColor = '#cbd5e1';
      });
      zoneEl.addEventListener('drop', (e) => {
        e.preventDefault();
        zoneEl.classList.remove('selected');
        zoneEl.style.borderColor = '#cbd5e1';
        const files = e.dataTransfer.files;
        if (files.length > 0) {
          inputEl.files = files;
          window.handleRecruitmentFileSelect({ target: inputEl }, dz.key);
        }
      });
    }
  });
  const corpBtn = document.getElementById('btn-corp-portal');
  if (corpBtn && typeof window.switchCareerPortal === 'function') {
    window.switchCareerPortal('corporate');
  }
});
function trackActiveNavLinks() {
  if (window.location.hash !== '' && window.location.hash !== '#home') return;
  const sections = document.querySelectorAll('section[id]');
  const navLinks = document.querySelectorAll('.nav-links a, .mobile-nav-links a');
  let currentActiveSectionId = '';
  sections.forEach(section => {
    const secId = section.getAttribute('id');
    if (secId === 'projects' || secId === 'documents') return;
    const sectionTop = section.offsetTop - 120;
    const sectionHeight = section.offsetHeight;
    if (window.scrollY >= sectionTop && window.scrollY < sectionTop + sectionHeight) {
      currentActiveSectionId = secId;
    }
  });
  if (currentActiveSectionId) {
    navLinks.forEach(link => {
      link.classList.remove('active');
      if (link.getAttribute('href') === `#${currentActiveSectionId}`) {
        link.classList.add('active');
      }
    });
  }
}
const mobileSidebar = document.getElementById('mobile-sidebar-menu');
const navOverlay = document.getElementById('nav-overlay');
const menuToggleBtn = document.getElementById('menu-toggle-btn');
const menuCloseBtn = document.getElementById('menu-close-btn');
if (menuToggleBtn && mobileSidebar && navOverlay) {
  menuToggleBtn.addEventListener('click', () => {
    mobileSidebar.classList.add('active');
    navOverlay.classList.add('active');
document.body.style.overflow = 'hidden';
  });
}
function closeMobileMenu() {
  if (mobileSidebar && navOverlay) {
    mobileSidebar.classList.remove('active');
    navOverlay.classList.remove('active');
document.body.style.overflow = 'auto';
  }
}
if (menuCloseBtn) {
  menuCloseBtn.addEventListener('click', closeMobileMenu);
}
if (navOverlay) {
  navOverlay.addEventListener('click', closeMobileMenu);
}
function scrollToTop() {
  window.scrollTo({
    top: 0,
    behavior: 'smooth'
  });
}
function validateEmail(email) {
  const regex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  return regex.test(email);
}
function validatePhone(phone) {
  const regex = /^[6-9]\d{9}$/;
  return regex.test(phone.replace(/[\s\-\+\(\)]/g, ''));
}
function highlightError(element, isValid) {
  if (isValid) {
    element.style.borderColor = 'var(--border-light)';
    element.style.backgroundColor = 'var(--light-bg)';
  } else {
    element.style.borderColor = '#ef4444';
    element.style.backgroundColor = '#fef2f2';
  }
}
function toggleButtonLoading(buttonEl, isLoading, originalText) {
  if (!buttonEl) return;
  if (isLoading) {
    buttonEl.disabled = true;
    buttonEl.classList.add('loading');
    buttonEl.innerHTML = `<span class="btn-spinner"></span> Sending...`;
  } else {
    buttonEl.disabled = false;
    buttonEl.classList.remove('loading');
    buttonEl.innerHTML = originalText;
  }
}
function redirectToWhatsApp(payload) {
  const waNumber = "918544071616";
  const messageText = `*Mildwave RO Booking Request*
----------------------------------------
*Customer Name:* ${payload.name}
*Mobile Number:* ${payload.phone}
*Email Address:* ${payload.email}
*City:* ${payload.city} (Pincode: ${payload.pincode})
*RO Type:* ${payload.type}
*Service Required:* ${payload.serviceType}
*Preferred Date:* ${payload.date}
*Preferred Slot:* ${payload.time}
*Service Address:* ${payload.address}
*Problem Details:* ${payload.message || 'None'}`;
  const encodedText = encodeURIComponent(messageText);
  const waUrl = `https://wa.me/${waNumber}?text=${encodedText}`;
  window.open(waUrl, '_blank');
}
function handleROSubmit(event) {
  event.preventDefault();
  const name = document.getElementById('ro-name');
  const phone = document.getElementById('ro-phone');
  const email = document.getElementById('ro-email');
  const city = document.getElementById('ro-city');
  const pincode = document.getElementById('ro-pincode');
  const type = document.getElementById('ro-type');
  const serviceType = document.getElementById('ro-service-type');
  const date = document.getElementById('ro-date');
  const time = document.getElementById('ro-time');
  const address = document.getElementById('ro-address');
  const message = document.getElementById('ro-message');
  let isValid = true;
  if (name.value.trim().length < 2) { highlightError(name, false); isValid = false; } else { highlightError(name, true); }
  if (!validatePhone(phone.value)) { highlightError(phone, false); isValid = false; } else { highlightError(phone, true); }
  if (!validateEmail(email.value)) { highlightError(email, false); isValid = false; } else { highlightError(email, true); }
  if (city.value.trim().length < 2) { highlightError(city, false); isValid = false; } else { highlightError(city, true); }
  if (pincode.value.trim().length !== 6 || isNaN(pincode.value.trim())) { highlightError(pincode, false); isValid = false; } else { highlightError(pincode, true); }
  if (type.value === '') { highlightError(type, false); isValid = false; } else { highlightError(type, true); }
  if (serviceType.value === '') { highlightError(serviceType, false); isValid = false; } else { highlightError(serviceType, true); }
  if (!date.value) { highlightError(date, false); isValid = false; } else { highlightError(date, true); }
  if (time.value === '') { highlightError(time, false); isValid = false; } else { highlightError(time, true); }
  if (address.value.trim().length < 5) { highlightError(address, false); isValid = false; } else { highlightError(address, true); }
  if (isValid) {
    const payload = {
      name: name.value.trim(),
      phone: phone.value.trim(),
      email: email.value.trim(),
      city: city.value.trim(),
      pincode: pincode.value.trim(),
      type: type.value,
      serviceType: serviceType.value,
      date: date.value,
      time: time.value,
      address: address.value.trim(),
      message: message ? message.value.trim() : ''
    };
    fetch(`${API_BASE}/api/booking`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(payload)
    }).catch(err => console.warn("[BACKGROUND POST FAILED]:", err));
    document.getElementById('ro-form-container').style.display = 'none';
    const successPanel = document.getElementById('ro-success-panel');
    successPanel.style.display = 'block';
    showToastNotification("Booking registered. Transferring to WhatsApp...");
    redirectToWhatsApp(payload);
  } else {
    showToastNotification("Please fill all required fields correctly.", "error");
  }
}
function resetROForm() {
  document.getElementById('ro-booking-form').reset();
  document.getElementById('ro-form-container').style.display = 'block';
  document.getElementById('ro-success-panel').style.display = 'none';
  const inputs = document.querySelectorAll('#ro-booking-form .form-control');
  inputs.forEach(el => highlightError(el, true));
}
const fileZone = document.getElementById('file-dropzone');
if (fileZone) {
  fileZone.addEventListener('dragover', (e) => {
    e.preventDefault();
    fileZone.classList.add('dragover');
  });
  fileZone.addEventListener('dragleave', () => {
    fileZone.classList.remove('dragover');
  });
  fileZone.addEventListener('drop', (e) => {
    e.preventDefault();
    fileZone.classList.remove('dragover');
    const files = e.dataTransfer.files;
    if (files.length > 0) {
      const fileInput = document.getElementById('career-resume');
      fileInput.files = files;
      updateFileUploadUI(files[0]);
    }
  });
}
window.handleRecruitmentFileSelect = function(event, key) {
  const file = event.target.files[0];
  if (!file) return;
  const zone = document.getElementById(`${key}-dropzone`);
  const title = document.getElementById(`${key}-title`);
  const meta = document.getElementById(`${key}-meta`);
  const sizeMB = (file.size / (1024 * 1024)).toFixed(2);
  const maxLimit = key.endsWith('photo') ? 2 * 1024 * 1024 : 5 * 1024 * 1024;
  const limitLabel = key.endsWith('photo') ? "2MB" : "5MB";
  if (file.size > maxLimit) {
    showToastNotification(`File size exceeds ${limitLabel} limit`, "error");
    event.target.value = '';
    if (zone) {
      zone.classList.remove('selected');
      zone.style.borderColor = '#ef4444';
    }
    return;
  }
  if (title && meta && zone) {
    title.textContent = file.name;
    meta.textContent = `File ready for upload (${sizeMB} MB)`;
    zone.classList.add('selected');
    zone.style.borderColor = 'var(--primary)';
  }
};
window.handleRecruitmentSubmit = function(event, portalType) {
  event.preventDefault();
  const prefix = portalType === 'corporate' ? 'corp' : 'man';
  const form = event.target;
  const inputs = form.querySelectorAll('.form-control[required]');
  let isValid = true;
  inputs.forEach(input => {
    if (input.value.trim() === '') {
      highlightError(input, false);
      isValid = false;
    } else {
      highlightError(input, true);
    }
  });
  const phone = document.getElementById(`${prefix}-phone`);
  if (phone && !validatePhone(phone.value)) {
    highlightError(phone, false);
    isValid = false;
  }
  const email = document.getElementById(`${prefix}-email`);
  if (email && email.value.trim() !== '') {
    if (!validateEmail(email.value)) {
      highlightError(email, false);
      isValid = false;
    }
  } else if (email && email.hasAttribute('required')) {
    if (!validateEmail(email.value)) {
      highlightError(email, false);
      isValid = false;
    }
  }
  const address = document.getElementById(`${prefix}-address`);
  if (address && address.value.trim().length < 5) {
    highlightError(address, false);
    isValid = false;
  }
  if (portalType === 'corporate') {
    const qualification = document.getElementById('corp-qualification');
    if (qualification && qualification.value.trim().length < 2) {
      highlightError(qualification, false);
      isValid = false;
    }
    const experience = document.getElementById('corp-experience');
    if (experience && experience.value.trim().length < 1) {
      highlightError(experience, false);
      isValid = false;
    }
    const skills = document.getElementById('corp-skills');
    if (skills && skills.value.trim().length < 2) {
      highlightError(skills, false);
      isValid = false;
    }
    const certifications = document.getElementById('corp-certifications');
    if (certifications && certifications.value.trim().length < 2) {
      highlightError(certifications, false);
      isValid = false;
    }
    const resumeInput = document.getElementById('corp-file-resume');
    const resumeZone = document.getElementById('corp-resume-dropzone');
    if (!resumeInput || resumeInput.files.length === 0) {
      if (resumeZone) resumeZone.style.borderColor = '#ef4444';
      isValid = false;
      showToastNotification("Resume upload is mandatory for professional roles.", "error");
    } else {
      if (resumeZone) resumeZone.style.borderColor = '#cbd5e1';
    }
  } else {
    const aadhaarNum = document.getElementById('man-aadhaar-num');
    if (aadhaarNum && (aadhaarNum.value.trim().length !== 12 || isNaN(aadhaarNum.value.trim()))) {
      highlightError(aadhaarNum, false);
      isValid = false;
      showToastNotification("Aadhaar Card Number must be exactly 12 digits.", "error");
    }
    const panNum = document.getElementById('man-pan-num');
    if (panNum && panNum.value.trim() !== '') {
      if (panNum.value.trim().length !== 10) {
        highlightError(panNum, false);
        isValid = false;
        showToastNotification("PAN Card Number must be exactly 10 characters.", "error");
      }
    }
    const education = document.getElementById('man-education');
    if (education && education.value === '') {
      highlightError(education, false);
      isValid = false;
    }
    const experience = document.getElementById('man-experience');
    if (experience && experience.value.trim().length < 1) {
      highlightError(experience, false);
      isValid = false;
    }
    const police = document.getElementById('man-police');
    if (police && police.value === '') {
      highlightError(police, false);
      isValid = false;
    }
    const relocate = document.getElementById('man-relocate');
    if (relocate && relocate.value === '') {
      highlightError(relocate, false);
      isValid = false;
    }
    const shift = document.getElementById('man-shift');
    if (shift && shift.value === '') {
      highlightError(shift, false);
      isValid = false;
    }
    const aadhaarInput = document.getElementById('man-file-aadhaar');
    const aadhaarZone = document.getElementById('man-aadhaar-dropzone');
    if (!aadhaarInput || aadhaarInput.files.length === 0) {
      if (aadhaarZone) aadhaarZone.style.borderColor = '#ef4444';
      isValid = false;
      showToastNotification("Aadhaar Card upload is mandatory.", "error");
    } else {
      if (aadhaarZone) aadhaarZone.style.borderColor = '#cbd5e1';
    }
    const photoInput = document.getElementById('man-file-photo');
    const photoZone = document.getElementById('man-photo-dropzone');
    if (!photoInput || photoInput.files.length === 0) {
      if (photoZone) photoZone.style.borderColor = '#ef4444';
      isValid = false;
      showToastNotification("Passport photograph is mandatory.", "error");
    } else {
      if (photoZone) photoZone.style.borderColor = '#cbd5e1';
    }
  }
  const recaptchaCheck = document.getElementById(`${prefix}-recaptcha-check`);
  if (recaptchaCheck && !recaptchaCheck.checked) {
    isValid = false;
    showToastNotification("Please complete the reCAPTCHA verification.", "error");
  }
  if (!isValid) {
    showToastNotification("Please check all required fields.", "error");
    return;
  }
  const submitBtn = form.querySelector('button[type="submit"]');
  const originalBtnText = submitBtn ? submitBtn.innerHTML : 'Submit Application';
  if (submitBtn) toggleButtonLoading(submitBtn, true);
  const progressContainer = document.getElementById(`${prefix}-submit-progress`);
  const progressPercent = document.getElementById(`${prefix}-progress-percent`);
  const progressFill = document.getElementById(`${prefix}-progress-fill`);
  if (progressContainer) progressContainer.style.display = 'block';
  const formData = new FormData(form);
  const xhr = new XMLHttpRequest();
  xhr.open('POST', `${API_BASE}/api/careers/${portalType}`, true);
  xhr.upload.addEventListener('progress', (e) => {
    if (e.lengthComputable) {
      const progress = Math.round((e.loaded / e.total) * 100);
      if (progressPercent) progressPercent.textContent = `${progress}%`;
      if (progressFill) progressFill.style.width = `${progress}%`;
    }
  });
  xhr.addEventListener('load', () => {
    if (submitBtn) toggleButtonLoading(submitBtn, false, originalBtnText);
    if (xhr.status === 200 || xhr.status === 201) {
      showToastNotification("Application submitted successfully!");
      form.style.display = 'none';
      const successPanel = document.getElementById('recruitment-success-panel');
      if (successPanel) successPanel.style.display = 'block';
      const successMsg = document.getElementById('recruitment-success-message');
      if (successMsg) {
        successMsg.textContent = "Thank you for applying to Mildwave Marketing Pvt. Ltd. Your application has been received successfully. Our HR team will review your profile and contact you if you are shortlisted.";
      }
      setTimeout(() => {
        if (progressContainer) progressContainer.style.display = 'none';
        if (progressPercent) progressPercent.textContent = '0%';
        if (progressFill) progressFill.style.width = '0%';
      }, 500);
    } else {
      let errMsg = "Submission failed. Please try again.";
      try {
        const res = JSON.parse(xhr.responseText);
        if (res.error) errMsg = res.error;
      } catch (ex) {}
      showToastNotification(errMsg, "error");
      setTimeout(() => {
        if (progressContainer) progressContainer.style.display = 'none';
      }, 500);
    }
  });
  xhr.addEventListener('error', () => {
    if (submitBtn) toggleButtonLoading(submitBtn, false, originalBtnText);
    showToastNotification("Network error occurred. Please try again.", "error");
    setTimeout(() => {
      if (progressContainer) progressContainer.style.display = 'none';
    }, 500);
  });
  xhr.send(formData);
};
function resetRecruitmentUploadUI(prefix) {
  const fields = ['resume', 'aadhaar', 'photo', 'pan'];
  fields.forEach(field => {
    const input = document.getElementById(`${prefix}-file-${field}`);
    if (input) input.value = '';
    const zone = document.getElementById(`${prefix}-${field}-dropzone`);
    if (zone) {
      zone.classList.remove('selected');
      zone.style.borderColor = '#cbd5e1';
    }
    const title = document.getElementById(`${prefix}-${field}-title`);
    const meta = document.getElementById(`${prefix}-${field}-meta`);
    if (title && meta) {
      if (field === 'resume') {
        title.textContent = "Click or drag & drop Resume here";
        meta.textContent = "PDF, DOC, or DOCX format (Max size 5MB)";
      } else if (field === 'aadhaar') {
        title.textContent = "Click or drag & drop Aadhaar Card here";
        meta.textContent = "PDF, JPG, JPEG, or PNG format (Max size 5MB)";
      } else if (field === 'photo') {
        title.textContent = "Click or drag & drop Photo here";
        meta.textContent = "JPG, JPEG, or PNG format (Max size 2MB)";
      } else if (field === 'pan') {
        title.textContent = "Click or drag & drop PAN Card here";
        meta.textContent = "PDF, JPG, JPEG, or PNG format (Max size 5MB)";
      }
    }
  });
  const inputs = document.querySelectorAll(`#${prefix === 'corp' ? 'corporate' : 'manpower'}-recruitment-form .form-control`);
  inputs.forEach(el => highlightError(el, true));
  const progress = document.getElementById(`${prefix}-submit-progress`);
  if (progress) progress.style.display = 'none';
}
function handleContactSubmit(event) {
  event.preventDefault();
  const name = document.getElementById('contact-name');
  const email = document.getElementById('contact-email');
  const phone = document.getElementById('contact-phone');
  const message = document.getElementById('contact-message');
  let isValid = true;
  if (name.value.trim().length < 2) { highlightError(name, false); isValid = false; } else { highlightError(name, true); }
  if (!validateEmail(email.value)) { highlightError(email, false); isValid = false; } else { highlightError(email, true); }
  if (!validatePhone(phone.value)) { highlightError(phone, false); isValid = false; } else { highlightError(phone, true); }
  if (message.value.trim().length < 10) { highlightError(message, false); isValid = false; } else { highlightError(message, true); }
  if (isValid) {
    const submitBtn = event.target.querySelector('button[type="submit"]');
    const originalBtnText = submitBtn ? submitBtn.innerHTML : 'Send Message';
    if (submitBtn) toggleButtonLoading(submitBtn, true);
    const payload = {
      name: name.value.trim(),
      email: email.value.trim(),
      phone: phone.value.trim(),
      message: message.value.trim()
    };
    fetch(`${API_BASE}/api/contact`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(payload)
    })
    .then(response => {
      if (!response.ok) throw new Error("Server error");
      return response.json();
    })
    .then(data => {
      if (submitBtn) toggleButtonLoading(submitBtn, false, originalBtnText);
      document.getElementById('contact-form-container').style.display = 'none';
      document.getElementById('contact-success-panel').style.display = 'block';
      showToastNotification("Message sent successfully!");
    })
    .catch(error => {
      console.error("Submission failed:", error);
      if (submitBtn) toggleButtonLoading(submitBtn, false, originalBtnText);
      showToastNotification("Something went wrong. Please try again.", "error");
    });
  } else {
    showToastNotification("Please fill in all contact details.", "error");
  }
}
